SELECT * FROM rally_meetup




ORDER BY biz_id DESC
LIMIT #{param.limit}

SELECT * FROM (
    (SELECT m.*, 'PENDING_APPROVAL' AS _pending_reason FROM rally_meetup m
     WHERE m.creator_id = #{userId}
       AND m.status IN ('OPEN','FULL') AND m.end_time > NOW()
       AND EXISTS (
           SELECT 1 FROM rally_meetup_registration r
           WHERE r.rally_meetup_id = m.biz_id AND r.status = 'PENDING'
       ))
    UNION
    (SELECT m.*, 'PENDING_REVIEW' AS _pending_reason FROM rally_meetup m
     WHERE (m.status = 'FINISHED' OR (m.status IN ('OPEN','FULL') AND m.end_time < NOW()))
       AND m.end_time + INTERVAL #{deadlineDays} DAY > NOW()
       AND EXISTS (
           SELECT 1 FROM rally_meetup_registration r
           WHERE r.rally_meetup_id = m.biz_id
             AND r.user_id = #{userId} AND r.status = 'JOINED'
       ))
    UNION

    (SELECT m.*, 'UNREAD_MESSAGES' AS _pending_reason FROM rally_meetup m
     WHERE EXISTS (
         SELECT 1 FROM rally_meetup_chat_user cu
         WHERE cu.meetup_id = m.biz_id AND cu.user_id = #{userId} AND cu.unread_count > 0
     )
     AND (
         m.creator_id = #{userId}
         OR EXISTS (
             SELECT 1 FROM rally_meetup_registration r
             WHERE r.rally_meetup_id = m.biz_id AND r.user_id = #{userId} AND r.status IN #{s}
         )
     ))
) t


        AND t.biz_id < #{lastId}


ORDER BY t.biz_id DESC
LIMIT #{limit}

SELECT * FROM rally_meetup m
WHERE (m.creator_id = #{userId}
   OR EXISTS (
       SELECT 1 FROM rally_meetup_registration r
       WHERE r.rally_meetup_id = m.biz_id AND r.user_id = #{userId} AND r.status IN #{s}
   ))

    AND m.biz_id < #{lastId}

ORDER BY m.biz_id DESC
LIMIT #{limit}
